#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;


//I'm too lazy to use a custom float here...
rand_preset = vec4(q6,q7,q8,q9);

// coloration of the red color channel
ret = vec3(1,1,1)*GetBlur3(vUv).x;
ret = mix( ret, rand_preset.yzx, GetBlur2(vUv).x*2);
ret = mix( ret, max(rand_preset.yxz*2,1), GetBlur1(vUv).x*0.5);
ret = mix( ret, -0.1*rand_preset.zwy, GetPixel(vUv).x);

//spinning vUv coordinates! (q2/3 are sin/cos calculations)
vec2 uv2 = vUv-.5;
uv2 = vec2((uv2.x)*q3 - (uv2.y) * q2,(uv2.x)* q2 + (uv2.y) * q3)+.5;

//adding some plasticity
vec2 d = uTexSize.zw*4;
float1 dx = ( GetBlur1(uv2+vec2(1,0)*d)-GetBlur1(uv2-vec2(1,0)*d) ).y;
float1 dy = ( GetBlur1(uv2+vec2(0,1)*d)-GetBlur1(uv2-vec2(0,1)*d) ).y;
vec2 uv_y = uv2+vec2(dx,dy)*0.4;

//coloration of the green color channel
ret = mix(ret,vec3(.8,.8,.8),texture(sampler_main,uv_y).y);
ret = mix( ret, rand_preset, GetBlur2(uv2).y*2);
ret = mix( ret, max(rand_preset*2,1.2), GetBlur1(uv_y).y*0.5);
ret = mix( ret, -.01*rand_preset.xyw, GetPixel(uv2).y);

//enable to check the warp shader
//ret = GetPixel(vUv);

  fragColor = ret;
}
